/**
 * REVENANT V31-F4 — "Block 4.5: Credit Eligibility Scorer (Mock Data Injector)"
 * Position: After Intent/Entity Extraction, before Credit Decision Engine.
 * Mocks an internal Credit Bureau lookup keyed off customer identity.
 * CRITICAL: No require('crypto'), no external libraries — pure JS only.
 */

const items = $input.all();
const returnData = [];

// ---------------------------------------------------------------------------
// MOCK CREDIT BUREAU — keyed by test identity for deterministic QA routing.
// ---------------------------------------------------------------------------
const MOCK_BUREAU = {
  'good@test.com':       { credit_score: 750, dbr: 30, fraud_flag: false, blacklist_status: false },
  'borderline@test.com': { credit_score: 650, dbr: 45, fraud_flag: false, blacklist_status: false },
  'bad@test.com':        { credit_score: 500, dbr: 60, fraud_flag: true,  blacklist_status: false },
};

// Fallback profile for any identity not in the mock bureau — fails closed
// (treated as high risk) rather than silently passing an unknown customer.
const UNKNOWN_PROFILE = { credit_score: 0, dbr: 100, fraud_flag: true, blacklist_status: false };

for (const item of items) {
  const ticket = item.json.canonical_ticket;

  // Locate intent across potential schema variations from upstream
  const intent = ticket?.rule_engine?.intent || ticket?.rule_based_intent;

  // Gracefully ignore anything that isn't a loan origination ticket.
  if (!ticket || intent !== 'LOAN_ORIGINATION') {
    returnData.push(item);
    continue;
  }

  // Identity lookup key: prefer email, fall back to the resolved P2P phone
  // target if that's the only identity attached to this ticket.
  const identityKey = (ticket.customer_email || ticket.p2p_target_canonical || '').toLowerCase();

  const bureauResult = MOCK_BUREAU[identityKey] || UNKNOWN_PROFILE;

  ticket.credit_profile = {
    ...bureauResult,
    identity_key: identityKey || null,
    source: 'MOCK_CREDIT_BUREAU',
    looked_up_at: new Date().toISOString(),
  };

  item.json.canonical_ticket = ticket;
  returnData.push(item);
}

return returnData;

/**
 * REVENANT V31-F4 — "Block 4.6: Credit Decision Engine (Strict Threshold Routing)"
 * Position: directly after Block 4.5: Credit Eligibility Scorer.
 * CRITICAL EXECUTION ORDER (do not reorder): AUTO_REJECT checked before
 * AUTO_APPROVE, so a single disqualifying factor can never be masked by an
 * otherwise-strong profile. Anything that survives both is REQUIRES_HITL.
 */

const items = $input.all();
const returnData = [];

for (const item of items) {
  const ticket = item.json.canonical_ticket;

  // Locate intent across potential schema variations from upstream
  const intent = ticket?.rule_engine?.intent || ticket?.rule_based_intent;

  // Gracefully ignore anything that isn't a loan origination ticket.
  if (!ticket || intent !== 'LOAN_ORIGINATION') {
    returnData.push(item);
    continue;
  }

  const profile = ticket.credit_profile || {};
  const credit_score = Number(profile.credit_score);
  const dbr = Number(profile.dbr);
  const fraud_flag = profile.fraud_flag === true;
  const blacklist_status = profile.blacklist_status === true;

  // Safely extract requested amount (if missing, becomes NaN)
  const requested_amount = Number(ticket.loan_request?.requested_amount);

  let status;
  let reason;

  // 1. AUTO_REJECT — evaluated first, any single trigger is disqualifying.
  if (credit_score < 600 || dbr > 50 || fraud_flag || blacklist_status) {
    status = 'AUTO_REJECT';
    const triggers = [];
    if (credit_score < 600) triggers.push('CREDIT_SCORE_BELOW_600');
    if (dbr > 50) triggers.push('DBR_ABOVE_50');
    if (fraud_flag) triggers.push('FRAUD_FLAG_TRUE');
    if (blacklist_status) triggers.push('BLACKLIST_STATUS_TRUE');
    reason = triggers.join(', ');

  // 2. AUTO_APPROVE — only reachable if reject rules above did not trigger.
  } else if (Number.isFinite(requested_amount) && requested_amount <= 5000000 && credit_score >= 700 && dbr < 40) {
    status = 'AUTO_APPROVE';
    reason = 'PASSED_AUTO_APPROVE_THRESHOLDS';

  // 3. FALLBACK — passed reject checks but missed an auto-approve threshold.
  } else {
    status = 'REQUIRES_HITL';
    const reasons = [];
    if (!Number.isFinite(requested_amount) || requested_amount > 5000000) reasons.push('AMOUNT_ABOVE_5M_OR_INVALID');
    if (credit_score < 700) reasons.push('SCORE_BELOW_700');
    if (dbr >= 40) reasons.push('DBR_AT_OR_ABOVE_40');
    reason = reasons.length ? reasons.join(', ') : 'BORDERLINE_PROFILE';
  }

  ticket.credit_decision = {
    status,
    reason,
    policy_version: 'V31_F4',
  };

  // false only for a hard reject; HITL still proceeds (true), same as approve.
  ticket.block46_passed = status !== 'AUTO_REJECT';

  item.json.canonical_ticket = ticket;
  returnData.push(item);
}

return returnData;

/**
 * REVENANT V31-F4 — "Block 4.7: e-Signature Dispatcher" (TIER 4)
 * Upgraded to explicitly route REQUIRES_HITL to Block 8.3 and build signatures.
 */

const items = $input.all();
const returnData = [];

function generatePureJSHash(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16);
}

for (const item of items) {
  const ticket = item.json.canonical_ticket;

  // Skip if not a loan
  if (!ticket || ticket.rule_based_intent !== 'LOAN_ORIGINATION') {
    returnData.push(item);
    continue;
  }

  const decision = item.json.credit_decision || {};

  // --- TIER 4 FIX: Route REQUIRES_HITL explicitly ---
  if (decision.status === 'REQUIRES_HITL') {
    if (!ticket.routing_decision) ticket.routing_decision = {};
    ticket.routing_decision.route = 'HITL_REVIEW'; // Block 8.3 catches this
    ticket.ticket_status = 'PENDING_HUMAN_REVIEW';
    ticket.block47_report = 'ROUTED_TO_HITL';

    // Provide a localized draft response for the delay
    if (!item.json.advisory) item.json.advisory = {};
    if (!item.json.advisory.llm_output) item.json.advisory.llm_output = {};
    item.json.advisory.llm_output.draft_customer_response = "Sizning kredit so'rovingiz qo'shimcha tekshirish uchun mutaxassislarimizga yuborildi. Tez orada siz bilan bog'lanamiz.";

    item.json.canonical_ticket = ticket;
    returnData.push(item);
    continue;
  }

  // --- EXISTING AUTO-APPROVE LOGIC (Preserved & Cleaned) ---
  if (decision.status === 'AUTO_APPROVE') {
     const amount = decision.approved_amount || ticket.transaction_amount;

     // 1. Generate Stateless Context Token
     const tokenPayload = {
       trace_id: ticket.trace_id,
       amount: amount,
       customer_id: ticket.customer_email || item.json.source_email || 'CUST-001',
       timestamp: Date.now()
     };

     // n8n safe base64 encoding
     const paymentToken = Buffer.from(JSON.stringify(tokenPayload)).toString('base64');
     const tokenSignature = generatePureJSHash(paymentToken);

     // 2. Build Telegram Button
     const telegramKeyboard = {
       inline_keyboard: [[
         {
           text: '✍️ Shartnomani Imzolash (Sign Contract)',
           callback_data: `SIGN_LOAN|${paymentToken}|${tokenSignature}`
         }
       ]]
     };

     if (!item.json.advisory) item.json.advisory = {};
     if (!item.json.advisory.llm_output) item.json.advisory.llm_output = {};

     item.json.advisory.llm_output.transaction_proposal = {
        tool_name: "LOAN_ORIGINATION",
        telegram_action: telegramKeyboard
     };
     item.json.advisory.llm_output.draft_customer_response = `Sizning ${amount} UZS miqdoridagi mikroqarzingiz ma'qullandi! Qabul qilish uchun quyidagi tugmani bosib shartnomani imzolang.`;

     ticket.block47_report = 'E_SIGNATURE_DISPATCHED';
     item.json.canonical_ticket = ticket;
     returnData.push(item);
     continue;
  }

  returnData.push(item);
}
return returnData;

/**
 * REVENANT V31-F4 — "Block 5.1: Credit Disbursement Trigger" (TIER 4)
 * Upgraded to include explicit customer/account identifiers in the payload.
 */

const items = $input.all();
const returnData = [];

for (const item of items) {
  const ticket = item.json.canonical_ticket;

  if (!ticket || ticket.routing_decision?.route !== 'LOAN_ORIGINATION' || item.json.status !== 'EXECUTE_LOAN') {
    returnData.push(item);
    continue;
  }

  // --- TIER 4 FIX: Add customer/account identifiers explicitly ---
  const customerId = ticket.customer_id || item.json.source_email || 'UNKNOWN_CUST_ID';
  const targetAccount = ticket.customer_wallet_id || ticket.p2p_target_canonical || 'ACC-DEFAULT-WALLET-01';
  const amount = ticket.transaction_amount;

  item.json.core_banking_request = {
    transaction_type: 'CREDIT_DISBURSEMENT',
    system_trace_id: ticket.trace_id,
    amount: amount,
    currency: 'UZS',
    // Newly added fields:
    customer_id: customerId,
    credit_account_id: targetAccount,
    debit_account_id: 'BANK-BULLION-ACC-001', 
    description: `Micro-loan disbursement for ${customerId}`,
    timestamp: new Date().toISOString()
  };

  ticket.block51_passed = true;
  ticket.block51_report = 'DISBURSEMENT_PAYLOAD_BUILT';
  item.json.canonical_ticket = ticket;

  returnData.push(item);
}

return returnData;

/**
 * REVENANT V31-F4 — "Block 5.0: Loan Signature Catcher"
 * Catches the SIGN_LOAN callback, verifies signature, decodes context.
 */

const items = $input.all();
const returnData = [];

function fnv1aHash(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16);
}

for (const item of items) {
  const callbackData = item.json.callback_data || item.json.body?.callback_query?.data || item.json.callback_query?.data || '';

  if (!callbackData.startsWith('SIGN_LOAN|')) {
    returnData.push(item);
    continue;
  }

  const parts = callbackData.split('|');
  const base64Payload = parts[1];
  const signature = parts[2];

  if (!base64Payload || !signature) {
    item.json.security_stop = true;
    item.json.error = 'Missing signature payload';
    returnData.push(item);
    continue;
  }

  if (fnv1aHash(base64Payload) !== signature) {
    item.json.security_stop = true;
    item.json.error = 'Signature tampering detected';
    returnData.push(item);
    continue;
  }

  // Decode stateless context
  const payloadStr = Buffer.from(base64Payload, 'base64').toString('utf8');
  const context = JSON.parse(payloadStr);

  // Rehydrate ticket
  const ticket = item.json.canonical_ticket || {};
  if (!ticket.routing_decision) ticket.routing_decision = {};
  ticket.routing_decision.route = 'LOAN_ORIGINATION';

  ticket.trace_id = context.trace_id;
  ticket.transaction_amount = context.amount;
  ticket.customer_id = context.customer_id; // Context safely injected!

  item.json.canonical_ticket = ticket;
  item.json.status = 'EXECUTE_LOAN';
  returnData.push(item);
}

return returnData;
